import React from 'react';
import { THEME } from '../tokens';
import { RADIUS, SHADOW, SHEEN, BLUR, type ShadowToken } from '../elevation';

/**
 * The Onda raised surface — the shared material behind cards, code blocks,
 * device/browser frames, and any panel. One primitive so every surface in the
 * catalog shares the same border, radius, shadow, and optional glass blur +
 * top sheen (CLAUDE.md §2 "Surface polish").
 *
 * Position/size it from the parent (wrap in `PlacementBox` or set width/height);
 * `Surface` only owns the material, not where it sits.
 */
export type SurfaceProps = {
  children?: React.ReactNode;
  width?: number | string;
  height?: number | string;
  /** `card` = opaque raised panel; `glass` = translucent + backdrop blur; `plain` = fill only. */
  variant?: 'card' | 'glass' | 'plain';
  radius?: number;
  padding?: number | string;
  /** Surface fill. Defaults per variant (surface token, or translucent for glass). */
  background?: string;
  borderColor?: string;
  shadow?: ShadowToken | 'none';
  /** Backdrop blur px for `glass`. Defaults to {@link BLUR.glass}. */
  blur?: number;
  /** Show the 1px top sheen. On by default for `card` / `glass`. */
  sheen?: boolean;
};

export const Surface: React.FC<SurfaceProps> = ({
  children,
  width,
  height,
  variant = 'card',
  radius = RADIUS.lg,
  padding,
  background,
  borderColor = THEME.border,
  shadow = variant === 'plain' ? 'none' : 'card',
  blur = BLUR.glass,
  sheen,
}) => {
  const isGlass = variant === 'glass';
  const showSheen = sheen ?? variant !== 'plain';
  const fill =
    background ?? (isGlass ? 'rgba(14,14,18,0.55)' : variant === 'plain' ? 'transparent' : THEME.surface);

  return (
    <div
      style={{
        position: 'relative',
        width,
        height,
        padding,
        borderRadius: radius,
        background: fill,
        border: `1px solid ${borderColor}`,
        boxShadow: shadow === 'none' ? undefined : SHADOW[shadow],
        backdropFilter: isGlass ? `blur(${blur}px)` : undefined,
        WebkitBackdropFilter: isGlass ? `blur(${blur}px)` : undefined,
        overflow: 'hidden',
      }}
    >
      {showSheen && (
        <div
          aria-hidden
          style={{
            position: 'absolute',
            inset: 0,
            borderRadius: radius,
            backgroundImage: SHEEN,
            pointerEvents: 'none',
          }}
        />
      )}
      <div style={{ position: 'relative' }}>{children}</div>
    </div>
  );
};

import React from 'react';
import { THEME } from '../tokens';

/**
 * A soft radial glow layer — the single restrained accent glow a section is
 * allowed (CLAUDE.md §2). Renders an absolutely-positioned, non-interactive
 * radial gradient; drop it behind content inside a positioned parent.
 *
 * Defaults to the Onda accent. Keep it to one per major moment — depth, not
 * decoration.
 */
export type GlowProps = {
  /** Glow color. Defaults to `--onda-accent`. */
  color?: string;
  /** Diameter as a fraction of the parent's smaller axis (0..1+). */
  size?: number;
  /** Center X / Y as 0..1 fractions of the parent. Default center. */
  x?: number;
  y?: number;
  /** Peak opacity at the center. */
  opacity?: number;
};

export const Glow: React.FC<GlowProps> = ({
  color = THEME.accent,
  size = 0.8,
  x = 0.5,
  y = 0.5,
  opacity = 0.35,
}) => {
  const radius = `${size * 60}%`;
  return (
    <div
      aria-hidden
      style={{
        position: 'absolute',
        inset: 0,
        pointerEvents: 'none',
        background: `radial-gradient(circle ${radius} at ${x * 100}% ${y * 100}%, ${color}, transparent 70%)`,
        opacity,
      }}
    />
  );
};

import React from 'react';
import { THEME } from '../tokens';

/**
 * A deterministic background grid — lines or dots — for technical / dashboard
 * surfaces. Pure CSS gradients, no per-cell elements, so it's cheap and
 * SSR-safe. Drop it as a full-bleed layer behind content.
 */
export type GridFieldProps = {
  /** Cell size in px. */
  cell?: number;
  /** `lines` = ruled grid; `dots` = dot lattice. */
  variant?: 'lines' | 'dots';
  /** Line/dot color. Defaults to `--onda-border`. */
  color?: string;
  /** Stroke thickness (lines) / dot radius px (dots). */
  thickness?: number;
  /** Layer opacity. Keep low — a grid is scaffold, not subject. */
  opacity?: number;
};

export const GridField: React.FC<GridFieldProps> = ({
  cell = 48,
  variant = 'lines',
  color = THEME.border,
  thickness = 1,
  opacity = 0.6,
}) => {
  const background =
    variant === 'dots'
      ? `radial-gradient(circle ${thickness}px at ${thickness}px ${thickness}px, ${color} 99%, transparent 100%)`
      : `linear-gradient(to right, ${color} ${thickness}px, transparent ${thickness}px), linear-gradient(to bottom, ${color} ${thickness}px, transparent ${thickness}px)`;
  return (
    <div
      aria-hidden
      style={{
        position: 'absolute',
        inset: 0,
        pointerEvents: 'none',
        opacity,
        backgroundImage: background,
        backgroundSize: `${cell}px ${cell}px`,
      }}
    />
  );
};

import React from 'react';
import { useVideoConfig } from 'remotion';

/**
 * A render-safe 2D camera. Renders an oversized "world" (its children, laid
 * out in world-pixel coordinates) and frames it: centers a world point in the
 * viewport at a given zoom, with optional roll. Used for pans across a grid
 * larger than the canvas, push-in "fly-overs", and focus moves that dim the
 * rest of a scene.
 *
 * Deliberately 2D — translate + scale + rotate only, `transform-style: flat`.
 * No `preserve-3d`: nested 3D contexts flatten unpredictably in Remotion's
 * render path, so depth is faked with layered children + per-layer scale/blur
 * instead — cheaper and fully deterministic (CLAUDE.md §1).
 *
 * Position/size is owned by the camera (it fills its positioned parent); lay
 * the children out in absolute world coordinates. Pair with {@link useCameraRig}
 * to interpolate focus/zoom/roll across keyframes.
 */
export type CameraProps = {
  /** The world — children laid out in absolute world-pixel coordinates. */
  children?: React.ReactNode;
  /** World x (px) to center in the viewport. Defaults to viewport center (no pan). */
  focusX?: number;
  /** World y (px) to center in the viewport. Defaults to viewport center (no pan). */
  focusY?: number;
  /** Zoom factor about the focus point. 1 = neutral, >1 = pushed in. */
  zoom?: number;
  /** Camera roll in degrees (2D rotation about the focus point). */
  rotate?: number;
  /** Override the viewport size; defaults to the Remotion canvas (`useVideoConfig`). */
  viewportWidth?: number;
  viewportHeight?: number;
};

export const Camera: React.FC<CameraProps> = ({
  children,
  focusX,
  focusY,
  zoom = 1,
  rotate = 0,
  viewportWidth,
  viewportHeight,
}) => {
  const config = useVideoConfig();
  const vw = viewportWidth ?? config.width;
  const vh = viewportHeight ?? config.height;
  const fx = focusX ?? vw / 2;
  const fy = focusY ?? vh / 2;

  // Map world point (fx, fy) to viewport center, then zoom + roll about it.
  // Read right-to-left: shift focus to origin → scale → rotate → recenter.
  const transform =
    `translate(${vw / 2}px, ${vh / 2}px) ` +
    `rotate(${rotate}deg) scale(${zoom}) ` +
    `translate(${-fx}px, ${-fy}px)`;

  return (
    <div style={{ position: 'absolute', inset: 0, overflow: 'hidden' }}>
      <div
        style={{
          position: 'absolute',
          left: 0,
          top: 0,
          transformOrigin: '0 0',
          transformStyle: 'flat',
          transform,
        }}
      >
        {children}
      </div>
    </div>
  );
};

// Shared visual primitives — the documented exception to the component
// contract's "self-contained" rule (CLAUDE.md §4): catalog components MAY
// import these building blocks. Keep this set small and material-level
// (surfaces, glows, fields) — not feature components.

export { Surface, type SurfaceProps } from './Surface';
export { Glow, type GlowProps } from './Glow';
export { GridField, type GridFieldProps } from './GridField';
export { Camera, type CameraProps } from './Camera';
export { MotionBlur, MotionTrail, type MotionBlurProps, type MotionTrailProps } from './MotionBlur';
